import React, { useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import authService from '../services/authService';

const parseParams = (value) => {
    if (!value) {
        return {};
    }
    return Object.fromEntries(new URLSearchParams(value));
};

const readRecoveryToken = () => {
    const hashParams = parseParams(window.location.hash.replace(/^#/, ''));
    const queryParams = parseParams(window.location.search.replace(/^\?/, ''));

    return (
        hashParams.access_token ||
        queryParams.access_token ||
        queryParams.token ||
        ''
    );
};

export default function ResetPassword() {
    const navigate = useNavigate();
    const token = useMemo(() => readRecoveryToken(), []);

    const [form, setForm] = useState({
        password: '',
        password_confirmation: '',
    });
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');
    const [loading, setLoading] = useState(false);

    const tokenMissing = !token;

    const handleChange = (event) => {
        const { name, value } = event.target;
        setForm((prev) => ({ ...prev, [name]: value }));
        setError('');
        setSuccess('');
    };

    const handleSubmit = async (event) => {
        event.preventDefault();

        if (tokenMissing) {
            setError('Invalid or expired reset link. Please request a new one.');
            return;
        }

        if (form.password !== form.password_confirmation) {
            setError('Passwords do not match.');
            return;
        }

        setLoading(true);
        setError('');
        setSuccess('');

        try {
            await authService.resetPassword({
                password: form.password,
                password_confirmation: form.password_confirmation,
                token,
            });

            setSuccess('Your password has been reset. Redirecting to login...');
            setTimeout(() => navigate('/login', { replace: true }), 1400);
        } catch (err) {
            setError(err.response?.data?.message || 'Unable to reset password. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="auth-page">
            <div className="auth-container">
                <div className="auth-modal auth-modal--login">
                    <div className="auth-modal__header">
                        <h1>CarVex Security</h1>
                        <button
                            type="button"
                            className="auth-modal__close"
                            aria-label="Close dialog"
                            onClick={() => navigate('/login')}
                        >
                            ×
                        </button>
                    </div>

                    <div className="auth-modal__body">
                        <div className="auth-header">
                            <h2>Reset Password</h2>
                            <p>Create a new password for your CarVex account.</p>
                        </div>

                        {error && <div className="alert alert-danger">{error}</div>}
                        {success && <div className="alert alert-success">{success}</div>}

                        <form onSubmit={handleSubmit} className="auth-form">
                            <div className="form-group">
                                <label htmlFor="password">New password</label>
                                <input
                                    type="password"
                                    id="password"
                                    name="password"
                                    value={form.password}
                                    onChange={handleChange}
                                    placeholder="Enter new password"
                                    required
                                    disabled={loading || tokenMissing}
                                />
                            </div>

                            <div className="form-group">
                                <label htmlFor="password_confirmation">Confirm password</label>
                                <input
                                    type="password"
                                    id="password_confirmation"
                                    name="password_confirmation"
                                    value={form.password_confirmation}
                                    onChange={handleChange}
                                    placeholder="Confirm new password"
                                    required
                                    disabled={loading || tokenMissing}
                                />
                            </div>

                            <button
                                type="submit"
                                className="btn btn-primary btn-block"
                                disabled={loading || tokenMissing}
                            >
                                {loading ? 'Updating password...' : 'Update Password'}
                            </button>
                        </form>

                        <div className="auth-footer auth-footer--center">
                            <p>
                                Back to <Link to="/login">Sign In</Link>
                            </p>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
